import{_ as e,o as d,c as r,a2 as s}from"./chunks/framework.DpRDjl8b.js";const g=JSON.parse('{"title":"SDD Depth Audit — 2026-07-07","description":"","frontmatter":{},"headers":[],"relativePath":"audit/SDD_DEPTH_AUDIT_2026-07-07.md","filePath":"audit/SDD_DEPTH_AUDIT_2026-07-07.md","lastUpdated":1784558854000}'),a={name:"audit/SDD_DEPTH_AUDIT_2026-07-07.md"};function o(i,t,n,l,c,u){return d(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="sdd-depth-audit-—-2026-07-07" tabindex="-1">SDD Depth Audit — 2026-07-07 <a class="header-anchor" href="#sdd-depth-audit-—-2026-07-07" aria-label="Permalink to &quot;SDD Depth Audit — 2026-07-07&quot;">​</a></h1><h2 id="contexte" tabindex="-1">Contexte <a class="header-anchor" href="#contexte" aria-label="Permalink to &quot;Contexte&quot;">​</a></h2><p>Une analyse externe (IA n&#39;ayant pas eu accès au dépôt) a identifié 5 domaines SDD prétendument « manquants » et recommandé leur spécification avant la V1. Cette revue vérifie ces affirmations contre le contenu réel des 26 volumes du SDD.</p><p><strong>Conclusion</strong> : l&#39;analyse externe est <strong>largement incorrecte</strong>. Les 26 volumes existent (~10 300 lignes), le gap analysis (<code>GAP_ANALYSIS_2.1.3_to_SDD.md</code>) est clos (940 tests, 0 échecs), et les sous-éléments prétendument absents sont pour la plupart spécifiés — souvent plus en détail que l&#39;analyse ne le supposait — ou sous des noms différents. Seuls <strong>9 écarts réels</strong> ont été identifiés et corrigés.</p><hr><h2 id="methodologie" tabindex="-1">Méthodologie <a class="header-anchor" href="#methodologie" aria-label="Permalink to &quot;Méthodologie&quot;">​</a></h2><ol><li>Lecture intégrale des 5 volumes ciblés (04, 06, 07, 08, 15) + volumes de référence (03, 05, 10, 17).</li><li>Vérification croisée : chaque sous-élément « absent » signalé par l&#39;analyse externe a été recherché dans tous les volumes, pas uniquement le volume principal.</li><li>Trois verdicts possibles : <strong>COVERED</strong> (spécifié, citation §/ligne), <strong>PARTIAL</strong> (existe mais mince/incomplet), <strong>ABSENT</strong> (réellement non spécifié).</li></ol><hr><h2 id="domaine-1-—-architecture-multi-agent-vol-08-248-lignes" tabindex="-1">Domaine 1 — Architecture Multi-Agent (Vol 08, 248 lignes) <a class="header-anchor" href="#domaine-1-—-architecture-multi-agent-vol-08-248-lignes" aria-label="Permalink to &quot;Domaine 1 — Architecture Multi-Agent (Vol 08, 248 lignes)&quot;">​</a></h2><p>L&#39;analyse externe réclamait : Scheduler, Queue, Worker, Reviewer, Proofreader, Glossary Agent, Context Agent, Quality Agent, Merge Agent — avec responsabilités, communication, états, timeout, retry.</p><h3 id="resultats" tabindex="-1">Résultats <a class="header-anchor" href="#resultats" aria-label="Permalink to &quot;Résultats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sous-élément</th><th>Verdict</th><th>Preuve</th></tr></thead><tbody><tr><td>Rôles (10 agents)</td><td>✅ COVERED</td><td>§8.2–§8.11 : Split, PreTranslate, Translate, Consistency, Lexicon, Grammar, Style, Polish, QA, Export</td></tr><tr><td>Responsabilités</td><td>✅ COVERED</td><td>Chaque agent : Mission / Entrées / Sorties / Règles. Acceptance §8.13</td></tr><tr><td>Communication inter-agents</td><td>⚠️ PARTIAL</td><td>Snapshot linéaire (§7.1 L29), <code>AgentContext</code> partagé (§8.1 L32–43). Pas de section nommée « communication » — mécanisme par design (pipeline strict, pas de bus de messages)</td></tr><tr><td>États</td><td>✅ COVERED</td><td>Job states §7.2 L42, Step states §7.3 L75. Agents stateless (instanciés par étape)</td></tr><tr><td>Timeout</td><td>❌ ABSENT → <strong>CORRIGÉ</strong></td><td>Aucun <code>timeoutMs</code> nulle part. Ajouté en G1</td></tr><tr><td>Retry</td><td>✅ COVERED</td><td>§7.8 L215–225 + §7.10 L239. Incohérence nombre → <strong>CORRIGÉ</strong> en G4</td></tr></tbody></table><h3 id="faux-signalements-dissipes" tabindex="-1">Faux signalements dissipés <a class="header-anchor" href="#faux-signalements-dissipes" aria-label="Permalink to &quot;Faux signalements dissipés&quot;">​</a></h3><ul><li><strong>Scheduler / Queue / Context « agents »</strong> : par design, ce sont des fonctions du WorkflowEngine et un objet injecté, pas des agents. En faire des agents serait un anti-pattern.</li><li><strong>Merge Agent</strong> : inutile — le pipeline est linéaire, pas de sharding parallèle.</li><li><strong>Reviewer / Proofreader / Glossary Agent / Quality Agent</strong> : noms génériques de l&#39;analyse externe. Le projet utilise une décomposition plus fine (10 agents), qui couvre ces fonctions.</li></ul><hr><h2 id="domaine-2-—-pipeline-de-traduction-vol-07-259-lignes" tabindex="-1">Domaine 2 — Pipeline de traduction (Vol 07, 259 lignes) <a class="header-anchor" href="#domaine-2-—-pipeline-de-traduction-vol-07-259-lignes" aria-label="Permalink to &quot;Domaine 2 — Pipeline de traduction (Vol 07, 259 lignes)&quot;">​</a></h2><p>L&#39;analyse externe réclamait un pipeline : Importer → Découpage → Extraction entités → Glossaire → Traduction → Révision IA → Terminologie → Incohérences → Fusion → Export.</p><h3 id="resultats-1" tabindex="-1">Résultats <a class="header-anchor" href="#resultats-1" aria-label="Permalink to &quot;Résultats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Étape réclamée</th><th>Verdict</th><th>Preuve</th></tr></thead><tbody><tr><td>Importer</td><td>✅ COVERED (cross-ref)</td><td>Vol 05 §5.4–§5.12 : import TXT/MD/DOCX/EPUB, encoding, langage, splitting</td></tr><tr><td>Découpage intelligent</td><td>✅ COVERED</td><td>§8.2 (SplitAgent) : mission, entrées, sorties, règles</td></tr><tr><td>Extraction des entités</td><td>✅ COVERED (cross-ref)</td><td>Vol 10 §10.8 : extraction automatique de termes candidats + classification IA</td></tr><tr><td>Glossaire</td><td>✅ COVERED</td><td>§8.6 (LexiconAgent) : locked terms, alias, case preservation</td></tr><tr><td>Traduction</td><td>✅ COVERED</td><td>§8.4 (TranslateAgent) + §8.3 (PreTranslateAgent)</td></tr><tr><td>Révision IA</td><td>✅ COVERED</td><td>Consistency §8.5 + QA §8.10 + Polish §8.9</td></tr><tr><td>Vérification terminologie</td><td>✅ COVERED</td><td>Lexicon §8.6 + Consistency caps §8.5</td></tr><tr><td>Détection incohérences</td><td>✅ COVERED</td><td>§8.5 (7 métriques, scoring pondéré)</td></tr><tr><td>Fusion</td><td>N/A</td><td>Pipeline linéaire, pas de sharding → pas besoin de merge</td></tr><tr><td>Export</td><td>✅ COVERED</td><td>§8.11 (ExportAgent) : formats, validation</td></tr></tbody></table><hr><h2 id="domaine-3-—-base-de-donnees-vol-06-233-lignes" tabindex="-1">Domaine 3 — Base de données (Vol 06, 233 lignes) <a class="header-anchor" href="#domaine-3-—-base-de-donnees-vol-06-233-lignes" aria-label="Permalink to &quot;Domaine 3 — Base de données (Vol 06, 233 lignes)&quot;">​</a></h2><p>L&#39;analyse externe réclamait : tables Projects/Books/Chapters/Paragraphs/Glossary/TM/Models/Providers/Jobs/Queue/Settings/History avec relations, indexes, migrations.</p><h3 id="resultats-2" tabindex="-1">Résultats <a class="header-anchor" href="#resultats-2" aria-label="Permalink to &quot;Résultats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Table réclamée</th><th>Verdict</th><th>Table réelle</th></tr></thead><tbody><tr><td>Projects</td><td>✅</td><td><code>projects</code></td></tr><tr><td>Books</td><td>❌ ABSENT</td><td>Hiérarchie <code>project → chapter</code> directe. <strong>Décision design documentée</strong> (G9)</td></tr><tr><td>Chapters</td><td>✅</td><td><code>chapters</code></td></tr><tr><td>Paragraphs</td><td>✅</td><td><code>paragraphs</code></td></tr><tr><td>Glossary</td><td>✅</td><td><code>lexicon</code> + <code>lexicon_aliases</code></td></tr><tr><td>TranslationMemory</td><td>✅</td><td><code>translation_memory</code></td></tr><tr><td>Models</td><td>✅</td><td><code>models</code></td></tr><tr><td>Providers</td><td>⚠️</td><td>Foldé dans <code>models.provider</code> (texte). Suffisant v1.0</td></tr><tr><td>Jobs</td><td>✅</td><td><code>jobs</code> + <code>job_steps</code></td></tr><tr><td>Queue</td><td>❌ ABSENT</td><td><code>jobs.status</code> fait office. <strong>Décision design documentée</strong> (G9)</td></tr><tr><td>Settings</td><td>✅</td><td><code>settings</code></td></tr><tr><td>History</td><td>✅</td><td><code>history</code></td></tr></tbody></table><p><strong>Indexes</strong> : 5 initiaux, insuffisants sur colonnes de statut → <strong>4 indexes ajoutés</strong> (G5).</p><p><strong>Relations</strong> : FK explicites avec <code>ON DELETE CASCADE</code> sur toutes les jointures. ✅</p><p><strong>Migrations</strong> : §6.4 (runner + versionning). ✅</p><hr><h2 id="domaine-4-—-ui-ux-vol-04-634-lignes" tabindex="-1">Domaine 4 — UI/UX (Vol 04, 634 lignes) <a class="header-anchor" href="#domaine-4-—-ui-ux-vol-04-634-lignes" aria-label="Permalink to &quot;Domaine 4 — UI/UX (Vol 04, 634 lignes)&quot;">​</a></h2><p>L&#39;analyse externe affirmait que l&#39;UI était « une des parties les moins détaillées » et réclamait un spec écran par écran (wireframe, composants, actions, raccourcis, états, erreurs).</p><h3 id="resultats-3" tabindex="-1">Résultats <a class="header-anchor" href="#resultats-3" aria-label="Permalink to &quot;Résultats&quot;">​</a></h3><p>Vol 04 est le <strong>volume le plus long</strong> (634 lignes, 18 sections). Il inclut : wireframes ASCII, catalogue de 15 composants avec Props, stores Pinia, breakpoints responsive, accessibilité, thèmes, états vides centralisés (§4.17), 3 parcours utilisateur critiques.</p><table tabindex="0"><thead><tr><th>Écran</th><th>Verdict</th><th>Détail</th></tr></thead><tbody><tr><td>Accueil</td><td>✅ COVERED</td><td>Wireframe (L132–152), actions, états vide/chargement/erreur</td></tr><tr><td>Projet</td><td>⚠️ → <strong>CORRIGÉ</strong></td><td>Manquait états chargement/vide/erreur. Ajoutés (G7)</td></tr><tr><td>Chapitres</td><td>⚠️ PARTIAL</td><td>Wireframe, actions. États minces (overlay workflow).</td></tr><tr><td>Lexique</td><td>⚠️ PARTIAL</td><td>Layout, tableau, formulaire, actions. Pas de wireframe.</td></tr><tr><td>Workflow</td><td>✅ COVERED</td><td>Pipeline graphique, icônes d&#39;état, logs temps réel, actions</td></tr><tr><td>Historique</td><td>⚠️ → <strong>CORRIGÉ</strong></td><td>14 lignes → 70+ lignes avec wireframe, composants, actions, états (G6)</td></tr><tr><td>Paramètres</td><td>⚠️ PARTIAL</td><td>5 sections détaillées. Pas de wireframe.</td></tr><tr><td>Console</td><td>⚠️ PARTIAL</td><td>Filtres, recherche, export. Pas de wireframe.</td></tr><tr><td>Mise à jour</td><td>✅ COVERED (cross-ref)</td><td>Vol 17 §17.9 + §17.4 : toast/modal, barre de progression, canal sélecteur</td></tr><tr><td>Monitoring</td><td>N/A</td><td>Par design (G9). L&#39;écran Workflow (§4.9) couvre le monitoring jobs</td></tr></tbody></table><p><strong>Raccourcis</strong> : design global (§4.15), pas par écran — choix délibéré.</p><hr><h2 id="domaine-5-—-plugins-et-providers-vol-15-335-lignes-vol-03-214-lignes" tabindex="-1">Domaine 5 — Plugins et Providers (Vol 15, 335 lignes + Vol 03, 214 lignes) <a class="header-anchor" href="#domaine-5-—-plugins-et-providers-vol-15-335-lignes-vol-03-214-lignes" aria-label="Permalink to &quot;Domaine 5 — Plugins et Providers (Vol 15, 335 lignes + Vol 03, 214 lignes)&quot;">​</a></h2><p>L&#39;analyse externe réclamait : Plugin API, Hooks, Lifecycle, Permissions, Sandbox, Version, Marketplace futur + ProviderManager, ModelCapabilities, RateLimiter, RetryPolicy, Streaming, Fallback, cost estimation.</p><h3 id="resultats-—-plugins-vol-15" tabindex="-1">Résultats — Plugins (Vol 15) <a class="header-anchor" href="#resultats-—-plugins-vol-15" aria-label="Permalink to &quot;Résultats — Plugins (Vol 15)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sous-élément</th><th>Verdict</th><th>Preuve</th></tr></thead><tbody><tr><td>Plugin API</td><td>✅</td><td>§15.4 : <code>NovelTradPlugin</code>, <code>PluginContext</code>, 7 méthodes <code>register*</code></td></tr><tr><td>Hooks</td><td>⚠️</td><td><code>activate/deactivate</code> + <code>registerConfigChangeListener</code>. Pas de hooks pipeline pré/post-étape (par design : contributions via <code>registerAgent</code>)</td></tr><tr><td>Lifecycle</td><td>✅</td><td>§15.6 : flowchart complet, hot-reload dev</td></tr><tr><td>Permissions</td><td>✅</td><td>§15.3 : 8 permissions, §15.7 : confirmation utilisateur, restrictions</td></tr><tr><td>Sandbox</td><td>⚠️</td><td>§15.7 L221–222 : pas de sandbox V8 en v1.0, compensations documentées</td></tr><tr><td>Version</td><td>⚠️ → <strong>CORRIGÉ</strong></td><td><code>apiVersion</code> field existe, pas de politique de compatibilité → ajoutée (G8)</td></tr><tr><td>Marketplace futur</td><td>✅</td><td>§15.8 L261–267 : planifié v2.0</td></tr></tbody></table><h3 id="resultats-—-providers-vol-03" tabindex="-1">Résultats — Providers (Vol 03) <a class="header-anchor" href="#resultats-—-providers-vol-03" aria-label="Permalink to &quot;Résultats — Providers (Vol 03)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sous-élément</th><th>Verdict</th><th>Preuve</th></tr></thead><tbody><tr><td>ProviderManager</td><td>⚠️</td><td>Fonction remplie par <code>AiRouter</code> (différent nom)</td></tr><tr><td>Provider interface</td><td>✅</td><td>§3.2 <code>AiProvider</code> : <code>chat</code>, <code>streamChat</code>, <code>embeddings</code>, <code>isAvailable</code></td></tr><tr><td>ModelCapabilities</td><td>⚠️</td><td>Matrice §3.6b, pas de type formel</td></tr><tr><td>RateLimiter</td><td>❌ ABSENT → <strong>CORRIGÉ</strong></td><td>Nouveau §3.7 (G2)</td></tr><tr><td>RetryPolicy</td><td>✅</td><td>§7.8 (retry ×3, backoff, fallback)</td></tr><tr><td>Streaming</td><td>✅</td><td><code>streamChat(): AsyncIterable&lt;string&gt;</code> §3.2</td></tr><tr><td>Fallback</td><td>✅</td><td>§3.5 : primary + fallback, pause si fallback échoue</td></tr><tr><td>Connection test</td><td>✅</td><td>§3.3 : <code>isAvailable()</code>, bouton « Tester » UI</td></tr><tr><td>Auto-benchmark</td><td>✅</td><td>§3.3 : latence, tokens/sec, RAM</td></tr><tr><td>Cost estimation</td><td>❌ ABSENT → <strong>CORRIGÉ</strong></td><td>Nouveau §3.8 (G3)</td></tr></tbody></table><hr><h2 id="ecarts-confirmes-et-corrections-appliquees" tabindex="-1">Écarts confirmés et corrections appliquées <a class="header-anchor" href="#ecarts-confirmes-et-corrections-appliquees" aria-label="Permalink to &quot;Écarts confirmés et corrections appliquées&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Écart</th><th>Volume</th><th>Correctif</th><th>Tier</th></tr></thead><tbody><tr><td>G1</td><td>Per-step <code>timeoutMs</code> absent</td><td>Vol 07</td><td>Ajouté <code>stepTimeoutMs</code> dans <code>WorkflowOptions</code> + <code>Step</code>, row erreur + critère acceptance</td><td>Tier 1</td></tr><tr><td>G2</td><td>RateLimiter absent</td><td>Vol 03</td><td>Nouveau §3.7 : <code>RateLimitConfig</code>, token bucket, 429 handling</td><td>Tier 1</td></tr><tr><td>G3</td><td>Estimation des coûts absente</td><td>Vol 03</td><td>Nouveau §3.8 : <code>ModelCostMetadata</code>, <code>estimateCost()</code>, accumulation par job, affichage UI</td><td>Tier 1</td></tr><tr><td>G4</td><td>Retry-count inconsistency (2 vs 3)</td><td>Vol 07 §7.8</td><td>Phrase de réconciliation : <code>maxRetries</code> (user) ≠ réseau retries (provider wrapper)</td><td>Tier 2</td></tr><tr><td>G5</td><td>Indexes insuffisants sur colonnes de statut</td><td>Vol 06 §6.3</td><td>+4 indexes (<code>paragraphs.status</code>, <code>jobs.status</code>, <code>job_steps.job_id</code>, <code>prompts.agent_id</code>), migration <code>012_index_coverage.sql</code></td><td>Tier 2</td></tr><tr><td>G6</td><td>Écran Historique trop mince (~14 lignes)</td><td>Vol 04 §4.10</td><td>Expansion : wireframe, <code>NtHistoryList</code>, actions (Restaurer/Comparer/Exporter/Supprimer), états (chargement/vide/erreur diff), raccourcis</td><td>Tier 2</td></tr><tr><td>G7</td><td>Écran Projet sans états</td><td>Vol 04 §4.6</td><td>Ajout états : chargement (squelettes), vide (CTA import), erreur (toast + retry)</td><td>Tier 2</td></tr><tr><td>G8</td><td><code>apiVersion</code> sans politique de compatibilité</td><td>Vol 15 §15.7</td><td>Paragraphe : accepte « 1.x », rejet avec erreur si incompatible, période de grâce, indépendance version/apiVersion</td><td>Tier 2</td></tr><tr><td>G9</td><td>Décisions design non documentées</td><td>Vol 06, Vol 04</td><td>Notes : pas de <code>books</code> (v2.0), pas de <code>queue</code> (jobs.status), pas de monitoring système (§4.9 suffit)</td><td>Tier 3</td></tr></tbody></table><hr><h2 id="volume-non-affectes" tabindex="-1">Volume non affectés <a class="header-anchor" href="#volume-non-affectes" aria-label="Permalink to &quot;Volume non affectés&quot;">​</a></h2><p>Aucun changement aux volumes 00–02, 05, 08–14, 16, 18–25. Les 26 volumes restent cohérents entre eux.</p><hr><h2 id="statistiques-finales" tabindex="-1">Statistiques finales <a class="header-anchor" href="#statistiques-finales" aria-label="Permalink to &quot;Statistiques finales&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Métrique</th><th style="text-align:right;">Avant</th><th style="text-align:right;">Après (specs)</th><th style="text-align:right;">Après (code)</th></tr></thead><tbody><tr><td>Volumes SDD</td><td style="text-align:right;">26</td><td style="text-align:right;">26 (inchangé)</td><td style="text-align:right;">26 (inchangé)</td></tr><tr><td>Lignes totales (estimées)</td><td style="text-align:right;">~10 300</td><td style="text-align:right;">~10 700 (+400)</td><td style="text-align:right;">~10 700</td></tr><tr><td>Écarts spec corrigés</td><td style="text-align:right;">—</td><td style="text-align:right;">9</td><td style="text-align:right;">9</td></tr><tr><td>Écarts code implémentés</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">6 (G1, G2, G3, G5, G7, G8)</td></tr><tr><td>Fausses alarmes dissipées</td><td style="text-align:right;">—</td><td style="text-align:right;">~31</td><td style="text-align:right;">~31</td></tr><tr><td>Tests</td><td style="text-align:right;">940</td><td style="text-align:right;">940 (docs only)</td><td style="text-align:right;"><strong>959</strong> (+19)</td></tr><tr><td>Type-check</td><td style="text-align:right;">0 erreurs</td><td style="text-align:right;">0 erreurs</td><td style="text-align:right;">0 erreurs</td></tr></tbody></table><blockquote><p><strong>Phase 2 (code)</strong> : les 6 écarts code réels ont été implémentés le 2026-07-07. G4 (retry reconciliation), G6 (Historique — code dépassait déjà la spec) et G9 (decision notes) étaient spec-only, déjà traités en Phase 1.</p></blockquote>',51)])])}const p=e(a,[["render",o]]);export{g as __pageData,p as default};
